<script setup lang="ts">
import { computed, onMounted, ref } from 'vue';
import { Head } from '@inertiajs/vue3';
import { AlertTriangle, Check, ChevronDown, ChevronRight, CircleDot, FolderTree, Pencil, Plus, RefreshCw, Search, ShieldCheck, Tags, Trophy, Users, X } from '@lucide/vue';
import AppShell from '../../Layouts/AppShell.vue';

type Position = { id:number; name:string; slug:string; is_active:boolean; athletes:number|null };
type Sport = { id:number; name:string; slug:string; is_active:boolean; sort_order:number; usage:{athletes:number|null;videos:number|null;opportunities:number|null}; positions:Position[] };
const sports=ref<Sport[]>([]),loading=ref(true),saving=ref(false),error=ref(''),notice=ref(''),query=ref(''),status=ref('all'),expanded=ref<number[]>([]),sportModal=ref(false),positionModal=ref(false),editingSport=ref<Sport|null>(null),editingPosition=ref<Position|null>(null),parentSport=ref<Sport|null>(null);
const sportForm=ref({name:'',sort_order:0,is_active:true}),positionForm=ref({name:'',is_active:true});
const csrf=()=>document.querySelector<HTMLMetaElement>('meta[name="csrf-token"]')?.content??'';
const api=async(url:string,options:RequestInit={})=>{const controller=new AbortController(),timer=window.setTimeout(()=>controller.abort(),15000);try{const response=await fetch(url,{credentials:'same-origin',...options,signal:controller.signal,headers:{Accept:'application/json','Content-Type':'application/json','X-CSRF-TOKEN':csrf(),...(options.headers||{})}});const payload=await response.json().catch(()=>({}));if(!response.ok)throw new Error(payload.message||Object.values(payload.errors||{}).flat()[0]||'Something went wrong.');return payload.data}finally{window.clearTimeout(timer)}};
const load=async()=>{loading.value=true;error.value='';try{sports.value=await api('/api/v1/admin/taxonomy')}catch(e:any){error.value=e.name==='AbortError'?'Taxonomy took too long to load. The request was stopped—tap Try again.':e.message}finally{loading.value=false}};
const stats=computed(()=>({sports:sports.value.length,active:sports.value.filter(x=>x.is_active).length,positions:sports.value.reduce((n,x)=>n+x.positions.length,0)}));
const filtered=computed(()=>sports.value.filter(item=>{const term=query.value.toLowerCase();const matches=!term||item.name.toLowerCase().includes(term)||item.slug.includes(term)||item.positions.some(x=>x.name.toLowerCase().includes(term));return matches&&(status.value==='all'||(status.value==='active')===item.is_active)}));
const toggle=(id:number)=>expanded.value=expanded.value.includes(id)?expanded.value.filter(x=>x!==id):[...expanded.value,id];
const openSport=(sport:Sport|null=null)=>{editingSport.value=sport;sportForm.value=sport?{name:sport.name,sort_order:sport.sort_order,is_active:sport.is_active}:{name:'',sort_order:sports.value.length*10,is_active:true};sportModal.value=true};
const openPosition=(sport:Sport,position:Position|null=null)=>{parentSport.value=sport;editingPosition.value=position;positionForm.value=position?{name:position.name,is_active:position.is_active}:{name:'',is_active:true};positionModal.value=true};
const saveSport=async()=>{saving.value=true;error.value='';try{await api(editingSport.value?`/api/v1/admin/taxonomy/sports/${editingSport.value.id}`:'/api/v1/admin/taxonomy/sports',{method:editingSport.value?'PATCH':'POST',body:JSON.stringify(sportForm.value)});sportModal.value=false;notice.value=editingSport.value?'Sport updated.':'Sport added.';await load()}catch(e:any){error.value=e.message}finally{saving.value=false}};
const savePosition=async()=>{if(!parentSport.value)return;saving.value=true;error.value='';try{await api(editingPosition.value?`/api/v1/admin/taxonomy/positions/${editingPosition.value.id}`:`/api/v1/admin/taxonomy/sports/${parentSport.value.id}/positions`,{method:editingPosition.value?'PATCH':'POST',body:JSON.stringify(positionForm.value)});positionModal.value=false;notice.value=editingPosition.value?'Position updated.':'Position added.';if(!expanded.value.includes(parentSport.value.id))expanded.value.push(parentSport.value.id);await load()}catch(e:any){error.value=e.message}finally{saving.value=false}};
const setSportActive=async(sport:Sport)=>{try{await api(`/api/v1/admin/taxonomy/sports/${sport.id}`,{method:'PATCH',body:JSON.stringify({is_active:!sport.is_active})});notice.value=`${sport.name} ${sport.is_active?'hidden':'activated'}.`;await load()}catch(e:any){error.value=e.message}};
const importCatalogue=async()=>{if(!confirm('Add missing recommended South African sports and positions? Existing taxonomy will not be overwritten.'))return;saving.value=true;error.value='';try{const controller=new AbortController(),timer=window.setTimeout(()=>controller.abort(),30000);const response=await fetch('/api/v1/admin/taxonomy/import-catalogue',{method:'POST',credentials:'same-origin',signal:controller.signal,headers:{Accept:'application/json','Content-Type':'application/json','X-CSRF-TOKEN':csrf()}});window.clearTimeout(timer);const payload=await response.json();if(!response.ok)throw new Error(payload.message||'Unable to import the catalogue.');notice.value=payload.message;await load()}catch(e:any){error.value=e.name==='AbortError'?'The catalogue import timed out. Please try again.':e.message}finally{saving.value=false}};
onMounted(load);
</script>

<template><Head title="Sports taxonomy"/><AppShell><main class="taxonomy-page">
  <header class="page-head"><div><span class="eyebrow"><FolderTree :size="14"/> PLATFORM STRUCTURE</span><h1>Sports taxonomy</h1><p>Manage the sports and playing positions used across profiles, content, discovery, and opportunities.</p></div><div class="head-actions"><button class="catalogue" :disabled="saving" @click="importCatalogue"><FolderTree :size="18"/> Recommended catalogue</button><button class="primary" @click="openSport()"><Plus :size="18"/> Add sport</button></div></header>
  <section class="stats"><article><span class="stat-icon violet"><Trophy/></span><div><small>Total sports</small><strong>{{stats.sports}}</strong><em>{{stats.active}} visible</em></div></article><article><span class="stat-icon blue"><Tags/></span><div><small>Positions</small><strong>{{stats.positions}}</strong><em>Across all sports</em></div></article><article><span class="stat-icon green"><Users/></span><div><small>Catalogue source</small><strong>Database</strong><em>Shared across the platform</em></div></article><article><span class="stat-icon pink"><ShieldCheck/></span><div><small>Data health</small><strong>{{sports.some(x=>!x.positions.length)?'Review':'Healthy'}}</strong><em>{{sports.filter(x=>!x.positions.length).length}} without positions</em></div></article></section>
  <p v-if="notice" class="flash success"><Check :size="16"/>{{notice}}<button @click="notice=''"><X :size="15"/></button></p><p v-if="error" class="flash error">{{error}}<button @click="error=''"><X :size="15"/></button></p>
  <section class="workspace"><header><div><h2>Sports and positions</h2><p>Inactive items stay attached to existing records but disappear from selection lists.</p></div><button class="refresh" :disabled="loading" @click="load"><RefreshCw :size="16" :class="{spin:loading}"/> Refresh</button></header>
    <div class="tools"><label><Search :size="17"/><input v-model="query" placeholder="Search sports or positions…"/></label><select v-model="status"><option value="all">All statuses</option><option value="active">Active only</option><option value="inactive">Inactive only</option></select></div>
    <div v-if="loading" class="empty"><RefreshCw class="spin"/><strong>Loading taxonomy…</strong><span>Reading sports and positions from the database.</span></div><div v-else-if="error&&!sports.length" class="empty error-empty"><AlertTriangle/><strong>Taxonomy could not load</strong><span>{{error}}</span><button class="primary" @click="load"><RefreshCw/> Try again</button></div><div v-else-if="!filtered.length" class="empty"><Search/><strong>{{sports.length?'No taxonomy items found':'No sports have been added'}}</strong><span>{{sports.length?'Try a different search or status.':'Add the first sport to start building the platform taxonomy.'}}</span><button v-if="!sports.length" class="primary" @click="openSport()"><Plus/> Add sport</button></div>
    <div v-else class="sport-list"><article v-for="sport in filtered" :key="sport.id" class="sport-card" :class="{muted:!sport.is_active}"><div class="sport-row">
      <button class="expand" @click="toggle(sport.id)"><ChevronDown v-if="expanded.includes(sport.id)"/><ChevronRight v-else/></button><span class="sport-mark">{{sport.name.slice(0,2).toUpperCase()}}</span><div class="sport-name"><div><strong>{{sport.name}}</strong><span :class="sport.is_active?'active':'inactive'">{{sport.is_active?'Active':'Hidden'}}</span></div><small>/{{sport.slug}} · Display order {{sport.sort_order}}</small></div>
      <div class="usage"><span><Tags/>{{sport.positions.length}} positions</span><span><CircleDot/>{{sport.positions.filter(x=>x.is_active).length}} selectable</span></div><div class="row-actions"><button title="Add position" @click="openPosition(sport)"><Plus/></button><button title="Edit sport" @click="openSport(sport)"><Pencil/></button><button class="switch" :class="{on:sport.is_active}" :aria-label="sport.is_active?'Hide sport':'Activate sport'" @click="setSportActive(sport)"><i/></button></div></div>
      <div v-if="expanded.includes(sport.id)" class="positions"><div class="position-head"><span>Playing positions</span><button @click="openPosition(sport)"><Plus :size="14"/> Add position</button></div><p v-if="!sport.positions.length" class="no-positions">No positions added yet. Add positions to improve athlete discovery.</p><div v-else class="position-grid"><button v-for="position in sport.positions" :key="position.id" class="position" :class="{muted:!position.is_active}" @click="openPosition(sport,position)"><CircleDot/><span><strong>{{position.name}}</strong><small>{{position.is_active?'Active and selectable':'Hidden from selection'}}</small></span><Pencil/></button></div></div>
    </article></div>
  </section>
  <div v-if="sportModal" class="overlay" @click.self="sportModal=false"><form class="modal" @submit.prevent="saveSport"><header><span class="modal-icon"><Trophy/></span><div><h2>{{editingSport?'Edit sport':'Add a sport'}}</h2><p>Used throughout profiles, feeds, and opportunities.</p></div><button type="button" @click="sportModal=false"><X/></button></header><label>Sport name<input v-model.trim="sportForm.name" maxlength="100" required placeholder="e.g. Football"/></label><label>Display order<input v-model.number="sportForm.sort_order" type="number" min="0" max="65535" required/><small>Lower numbers appear first in selection lists.</small></label><label class="check"><input v-model="sportForm.is_active" type="checkbox"/><span><strong>Active and selectable</strong><small>Members can select this sport on new records.</small></span></label><footer><button type="button" @click="sportModal=false">Cancel</button><button class="primary" :disabled="saving" type="submit">{{saving?'Saving…':'Save sport'}}</button></footer></form></div>
  <div v-if="positionModal" class="overlay" @click.self="positionModal=false"><form class="modal" @submit.prevent="savePosition"><header><span class="modal-icon"><Tags/></span><div><h2>{{editingPosition?'Edit position':'Add position'}}</h2><p>{{parentSport?.name}}</p></div><button type="button" @click="positionModal=false"><X/></button></header><label>Position name<input v-model.trim="positionForm.name" maxlength="100" required placeholder="e.g. Goalkeeper"/></label><label class="check"><input v-model="positionForm.is_active" type="checkbox"/><span><strong>Active and selectable</strong><small>Members can select this position on their profiles.</small></span></label><footer><button type="button" @click="positionModal=false">Cancel</button><button class="primary" :disabled="saving" type="submit">{{saving?'Saving…':'Save position'}}</button></footer></form></div>
</main></AppShell></template>

<style scoped>
.taxonomy-page{max-width:1240px;margin:auto;padding:38px 30px 80px;color:#172033}.page-head{display:flex;align-items:flex-end;justify-content:space-between;gap:24px;margin-bottom:26px}.page-head h1{font-size:32px;letter-spacing:-.8px;margin:7px 0}.page-head p,.workspace header p{color:#68758c;margin:0}.eyebrow{display:flex;align-items:center;gap:7px;color:#c34d91;font-size:12px;font-weight:800;letter-spacing:.09em}.primary{border:0;background:linear-gradient(135deg,#536ff1,#8b5ce7);color:#fff;border-radius:12px;padding:12px 18px;font-weight:750;display:flex;align-items:center;justify-content:center;gap:8px;box-shadow:0 8px 22px #536ff12a}.stats{display:grid;grid-template-columns:repeat(4,1fr);gap:14px;margin-bottom:22px}.stats article{background:#fff;border:1px solid #dfe5ef;border-radius:16px;padding:19px;display:flex;gap:14px;align-items:center;box-shadow:0 8px 25px #26364e0a}.stats small,.stats em{display:block;color:#758198;font-style:normal;font-size:12px}.stats strong{display:block;font-size:22px;margin:3px 0}.stat-icon{width:44px;height:44px;border-radius:13px;display:grid;place-items:center}.stat-icon svg{width:21px}.violet{background:#f0eafe;color:#7855dc}.blue{background:#e8f2ff;color:#3977e9}.green{background:#e8f8f1;color:#25a46d}.pink{background:#fdeaf4;color:#d34e94}.flash{display:flex;align-items:center;gap:8px;border-radius:11px;padding:11px 14px;font-size:14px}.flash.success{background:#e9f8f1;color:#187c53}.flash.error{background:#fff0f2;color:#be334e}.flash button{margin-left:auto;border:0;background:none;color:inherit}.workspace{background:#fff;border:1px solid #dfe5ef;border-radius:18px;overflow:hidden;box-shadow:0 14px 40px #26364e0d}.workspace>header{display:flex;justify-content:space-between;align-items:center;padding:22px 24px;border-bottom:1px solid #e7ebf2}.workspace h2{margin:0 0 5px;font-size:19px}.refresh{border:1px solid #dce2ec;background:#fff;border-radius:10px;padding:9px 12px;display:flex;gap:7px;align-items:center}.tools{padding:15px 24px;display:flex;gap:10px;background:#fafbfe;border-bottom:1px solid #e7ebf2}.tools label{flex:1;display:flex;align-items:center;gap:9px;background:#fff;border:1px solid #dce2ec;border-radius:10px;padding:0 12px;color:#8994a7}.tools input{width:100%;border:0;outline:0;padding:11px 0;font:inherit}.tools select{border:1px solid #dce2ec;border-radius:10px;background:#fff;padding:0 34px 0 12px}.sport-list{padding:10px}.sport-card{border:1px solid #e3e7ef;border-radius:14px;margin-bottom:9px;overflow:hidden}.sport-card.muted{background:#fafafa}.sport-row{display:flex;align-items:center;gap:12px;padding:15px}.expand,.row-actions button{border:0;background:transparent;color:#758198;display:grid;place-items:center}.expand svg,.row-actions svg{width:18px}.sport-mark{width:42px;height:42px;display:grid;place-items:center;border-radius:12px;background:linear-gradient(135deg,#ede9ff,#fae8f2);color:#7652c6;font-weight:850}.sport-name{min-width:215px}.sport-name>div{display:flex;align-items:center;gap:8px}.sport-name small{color:#8390a4}.sport-name span{font-size:10px;font-weight:800;padding:3px 7px;border-radius:20px}.active{background:#e5f8ef;color:#21845c}.inactive{background:#edf0f4;color:#6f7887}.usage{display:flex;gap:20px;margin-left:auto}.usage span{color:#67748a;font-size:12px;display:flex;align-items:center;gap:5px}.usage svg{width:14px}.row-actions{display:flex;align-items:center;gap:5px}.row-actions>button:not(.switch){width:34px;height:34px;border:1px solid #e1e6ee;border-radius:9px;background:#fff}.switch{width:38px;height:22px!important;border-radius:20px!important;background:#c9d0dc!important;padding:3px!important}.switch i{width:16px;height:16px;background:white;border-radius:50%;display:block;transition:.2s}.switch.on{background:#665de1!important}.switch.on i{transform:translateX(16px)}.positions{padding:4px 20px 18px 74px;border-top:1px solid #edf0f5;background:#fbfcfe}.position-head{display:flex;align-items:center;justify-content:space-between;padding:13p